export async function GET(req: Request) {
  const url   = new URL(req.url)
  const model = url.searchParams.get('model')   // 'a25' | 'ec230' | 'all'
  const exec  = url.searchParams.get('exec')    // 'true' to actually run

  const db = createAdminSupabase()

  // Get modelo IDs
  const { data: modelos } = await db.from('modelos').select('id, codigo')
  const a25Row  = modelos?.find(m => m.codigo === 'A25J')
  const ec230Row = modelos?.find(m => m.codigo === 'EC230FL3')

  if (!exec || exec !== 'true') {
    return NextResponse.json({
      a25_id:  a25Row?.id,
      ec230_id: ec230Row?.id,
      a25_count:  A25_ITEMS.length,
      ec230_count: EC230_ITEMS.length,
      msg: 'Add ?exec=true to run the reseed'
    })
  }

  const results: Record<string, unknown> = {}

  if ((!model || model === 'a25' || model === 'all') && a25Row) {
    await db.from('items').delete().eq('modelo_id', a25Row.id)
    const rows = A25_ITEMS.map((it, idx) => ({ ...it, modelo_id: a25Row.id, orden: idx }))
    const { data, error } = await db.from('items').insert(rows as never[]).select('id')
    results['a25'] = error ? { error: error.message } : { inserted: data?.length }
  }

  if ((!model || model === 'ec230' || model === 'all') && ec230Row) {
    await db.from('items').delete().eq('modelo_id', ec230Row.id)
    const rows = EC230_ITEMS.map((it, idx) => ({ ...it, modelo_id: ec230Row.id, orden: idx }))
    const { data, error } = await db.from('items').insert(rows as never[]).select('id')
    results['ec230'] = error ? { error: error.message } : { inserted: data?.length }
  }

  return NextResponse.json(results)
}
